const STAT_GUIDE=[
{term:"Points percentage",source:"NHL",text:"Points earned divided by the maximum points available. It compares teams fairly when they have played different numbers of games."},
{term:"Goal differential",source:"NHL",text:"Goals scored minus goals allowed. A positive number means the team has outscored its opponents."},
{term:"Expected goals",source:"MoneyPuck",text:"The estimated number of goals created by a set of shots, based on factors such as location, angle and the events before the shot."},
{term:"Expected goals share",source:"MoneyPuck",text:"The percentage of total expected goals belonging to a team or player while on the ice. Above 50% means the better share of scoring chances."},
{term:"Game expected goals",source:"MoneyPuck",text:"The expected goals generated by one team in a single game. It estimates the scoring value of that team's shots rather than simply counting them."},
{term:"Game xG share",source:"MoneyPuck",text:"A team's expected goals divided by both teams' expected goals in one game. Above 50% means it produced the stronger quality-adjusted chance profile."},
{term:"Game shot-attempt share",source:"MoneyPuck",text:"The percentage of all shot attempts belonging to one team in a game. It includes shots on goal, misses and blocks and is also called game Corsi percentage."},
{term:"Goals saved above expected",source:"MoneyPuck",text:"Expected goals against minus actual goals allowed. Positive values indicate more goals saved than an average goalie would be expected to save."},
{term:"GSAx",source:"MoneyPuck",text:"Short for goals saved above expected. It adjusts goalie performance for the quality of shots faced."},
{term:"Corsi",source:"MoneyPuck",text:"Share of all shot attempts: shots on goal, missed shots and blocked shots. It is commonly used as a possession indicator."},
{term:"Fenwick",source:"MoneyPuck",text:"Share of unblocked shot attempts: shots on goal plus missed shots. Blocked attempts are excluded."},
{term:"High-danger shots",source:"NHL",text:"NHL EDGE defines these as shots from its closest central scoring region. MoneyPuck uses a model-based goal-probability threshold, so values from the two sources should not be mixed."},
{term:"High-danger balance",source:"MoneyPuck",text:"High-danger attempts created minus high-danger attempts allowed. Positive values mean the team created more dangerous opportunities."},
{term:"Relative expected goals",source:"MoneyPuck",text:"A player's on-ice expected-goals share minus the team's share while that player is off the ice."},
{term:"Tracker Power Index",source:"Tracker",text:"Our transparent blend of points percentage, MoneyPuck expected-goals share and goal differential per game. It is not MoneyPuck's proprietary Power Score."},
{term:"Maximum skating speed",source:"NHL",text:"The highest sustained skating speed recorded for a player by NHL EDGE tracking."},
{term:"Skating speed bursts",source:"NHL",text:"The number of sustained skating efforts above NHL EDGE speed thresholds such as 20 or 22 miles per hour."},
{term:"Distance per 60",source:"NHL",text:"Skating distance normalized to 60 minutes of ice time, allowing players with different workloads to be compared."},
{term:"Average shot speed",source:"NHL",text:"Average speed of recorded shot attempts, including saved, missed and blocked attempts."},
{term:"Zone time",source:"NHL",text:"The percentage of game-clock time the puck spends in each zone while a player is on the ice or a team is playing."},
{term:"5-on-5 save percentage",source:"NHL",text:"The percentage of shots stopped while both teams have five skaters and a goalie on the ice."},
{term:"Close-situation save percentage",source:"NHL",text:"5-on-5 save percentage when tied in periods one or two, or within one goal in the third period."},
{term:"Save percentage above expected",source:"MoneyPuck",text:"Actual save percentage minus the save percentage expected from the quality of shots faced."},
{term:"Power-play pace",source:"Tracker",text:"A season projection based on the current rate. Projections describe pace, not certainty."},
{term:"Regulation wins",source:"NHL",text:"Wins earned without overtime or a shootout. They are used as an NHL standings tiebreaker."}
,{term:"Five-on-five (5v5)",source:"Natural Stat Trick",text:"Play with five skaters and one goalie on each team. Removing power plays and penalty kills makes even-strength performance easier to compare."}
,{term:"Score and venue adjusted",source:"Natural Stat Trick",text:"Shot-based results adjusted for the score of the game and for rink-recording differences. This makes team comparisons fairer than raw counts alone."}
,{term:"Per 60",source:"Natural Stat Trick",text:"A rate scaled to 60 minutes of ice time. It compares production between players who have played different amounts."}
,{term:"CF%",source:"Natural Stat Trick",text:"Corsi For percentage: a team's or player's share of all shot attempts at five-on-five. Above 50% means more attempts for than against."}
,{term:"FF%",source:"Natural Stat Trick",text:"Fenwick For percentage: the share of unblocked shot attempts. Shots on goal and missed shots count; blocked attempts do not."}
,{term:"SF%",source:"Natural Stat Trick",text:"Shots For percentage: the share of shots on goal taken by a team while play is at five-on-five."}
,{term:"xGF%",source:"Natural Stat Trick",text:"Expected Goals For percentage: the share of total expected goals created by a team. Above 50% indicates the stronger quality-adjusted chance share."}
,{term:"SCF%",source:"Natural Stat Trick",text:"Scoring Chances For percentage: the share of scoring chances belonging to a team while it is on the ice."}
,{term:"HDCF%",source:"Natural Stat Trick",text:"High-Danger Chances For percentage: the share of the most dangerous scoring chances belonging to a team."}
,{term:"PDO",source:"Natural Stat Trick",text:"Shooting percentage plus save percentage, commonly shown around a 100 baseline. Large departures can reflect finishing, goaltending and results that may not persist."}
,{term:"Individual expected goals (ixG)",source:"Natural Stat Trick",text:"The expected-goal value of an individual player's own shots, based on the quality of those attempts."}
,{term:"Individual scoring chances (iSCF)",source:"Natural Stat Trick",text:"The number of scoring-chance attempts taken by an individual player."}
,{term:"Individual high-danger chances (iHDCF)",source:"Natural Stat Trick",text:"The number of a player's own attempts classified as high-danger scoring chances."}
,{term:"Individual points percentage (IPP)",source:"Natural Stat Trick",text:"The percentage of on-ice goals for on which a player recorded a goal or assist."}
,{term:"Rush attempts",source:"Natural Stat Trick",text:"Shot attempts generated from a rush attack rather than established offensive-zone possession."}
,{term:"Rebounds created",source:"Natural Stat Trick",text:"A player's shot attempts that produced a rebound opportunity."}
,{term:"Goals saved above average (GSAA)",source:"Natural Stat Trick",text:"Goals an average goaltender would have allowed on the same number of shots minus the goalie's actual goals allowed. Positive is better."}
,{term:"High-danger save percentage",source:"Natural Stat Trick",text:"The percentage of high-danger shots on goal stopped by a goalie. It can vary substantially in small samples."}
,{term:"Medium-danger save percentage",source:"Natural Stat Trick",text:"The percentage of medium-danger shots on goal stopped by a goalie."}
,{term:"Low-danger save percentage",source:"Natural Stat Trick",text:"The percentage of low-danger shots on goal stopped by a goalie."}
,{term:"Primary points",source:"Natural Stat Trick",text:"Goals plus first assists. This isolates the players most directly involved in producing a goal."}
,{term:"Penalty impact",source:"Tracker",text:"Penalties drawn minus penalties taken in the Natural Stat Trick export. Positive values indicate a player earned more power plays than they conceded."}
,{term:"Player impact profile",source:"Tracker",text:"The average of position-adjusted five-on-five percentiles for primary points, expected goals, high-danger chances, rush attempts, takeaways and penalty impact. It is a descriptive profile, not a complete player rating."}
,{term:"Medium-danger chance share",source:"Natural Stat Trick",text:"The percentage of all medium-danger chances created by a team. Above 50% means it created more than it allowed."}
,{term:"Low-danger chance share",source:"Natural Stat Trick",text:"The percentage of all low-danger chances created by a team. It describes territorial volume farther from the most dangerous scoring areas."}
,{term:"Danger-level GSAA",source:"Natural Stat Trick",text:"Goals saved above average separated into high-, medium- and low-danger shots. It shows where a goalie's results were gained or lost."}
,{term:"Cap hit",source:"PuckPedia",text:"The amount of a player's contract charged against the team salary cap for a season. It can differ from the cash salary paid that year."}
,{term:"Average annual value (AAV)",source:"PuckPedia",text:"The average yearly value of a contract. Salary, signing bonuses and applicable performance bonuses are spread across the contract term."}
,{term:"Salary",source:"PuckPedia",text:"The actual compensation paid to a player in a specific season, including applicable signing bonuses. It may differ from cap hit."}
,{term:"UFA",source:"PuckPedia",text:"Unrestricted free agent. When the contract expires, the player can generally negotiate and sign with any team."}
,{term:"RFA",source:"PuckPedia",text:"Restricted free agent. The current team retains certain negotiating and matching rights after the contract expires."}
,{term:"No-movement clause (NMC)",source:"PuckPedia",text:"A contract clause that prevents a player being traded, waived or assigned to the minors without the player's approval."}
,{term:"No-trade clause (NTC)",source:"PuckPedia",text:"A contract clause that restricts trades without player approval. A modified NTC usually specifies an agreed list of teams."}
,{term:"Games played (GP)",source:"NHL",text:"The number of games in which a team or player officially participated."}
,{term:"Wins, losses and overtime losses (W-L-OTL)",source:"NHL",text:"A team's record. Wins earn two standings points; an overtime or shootout loss earns one; a regulation loss earns none."}
,{term:"Points (PTS)",source:"NHL",text:"For teams, standings points earned from results. For skaters, goals plus assists."}
,{term:"Goals for and against (GF-GA)",source:"NHL",text:"Goals scored and goals allowed. The difference between them is goal differential."}
,{term:"Last 10",source:"NHL",text:"A team's record or performance across its ten most recently completed games."}
,{term:"Streak",source:"NHL",text:"Consecutive results of the same kind, such as W4 for four straight wins or L2 for two straight losses."}
,{term:"Wildcard rank",source:"NHL",text:"A team's position among the non-automatic playoff qualifiers in its conference."}
,{term:"Projected 82-game pace",source:"Tracker",text:"The current rate of team points extended across an 82-game schedule. It is a projection, not a prediction."}
,{term:"Maximum possible points",source:"Tracker",text:"Current points plus two points for every remaining regular-season game. It shows the mathematical ceiling."}
,{term:"Required record",source:"Tracker",text:"A simplified estimate of the wins or equivalent standings points needed to reach the displayed playoff target."}
,{term:"Shots on goal (SOG)",source:"NHL",text:"Shot attempts that would enter the net unless stopped by the goaltender. Goals are included; missed and blocked attempts are not."}
,{term:"Shot attempt",source:"NHL",text:"Any attempt directed toward goal, including shots on goal, missed shots and blocked shots."}
,{term:"Shooting percentage",source:"NHL",text:"Goals divided by shots on goal. It describes how often recorded shots become goals."}
,{term:"Save percentage (SV%)",source:"NHL",text:"Saves divided by shots on goal faced. A higher value means a greater share of shots was stopped."}
,{term:"Goals-against average (GAA)",source:"NHL",text:"Goals allowed per 60 minutes of goaltending time."}
,{term:"Time on ice (TOI)",source:"NHL",text:"The amount of game time a player spent on the ice. The tracker also uses TOI cutoffs to avoid unstable small samples."}
,{term:"Penalty minutes (PIM)",source:"NHL",text:"Minutes charged for penalties. It does not always equal the exact time a team played shorthanded."}
,{term:"Expected goals for and against (xGF-xGA)",source:"MoneyPuck",text:"Modelled goals created and conceded based on shot quality. Comparing the two describes the expected balance of play."}
,{term:"Goals above expected",source:"MoneyPuck",text:"Actual goals minus expected goals from a player's shots. Positive values indicate finishing above the modelled expectation."}
,{term:"Expected save percentage (xSV%)",source:"MoneyPuck",text:"The save percentage an average goaltender would be expected to post against the same mix of shots."}
,{term:"Rebounds above expected",source:"MoneyPuck",text:"The difference between rebounds allowed and the model's expectation. Interpretation depends on the provider's sign convention shown with the value."}
,{term:"On-ice expected-goals share",source:"MoneyPuck",text:"The percentage of expected goals belonging to a player's team while that player is on the ice."}
,{term:"Line combination",source:"MoneyPuck",text:"A forward line or defence pairing observed together. Minutes show usage, not a confirmed future lineup."}
,{term:"Faceoff percentage",source:"Natural Stat Trick",text:"The share of recorded faceoffs won by a player or team."}
,{term:"Takeaway",source:"Natural Stat Trick",text:"A recorded play in which a player gains possession by taking the puck from an opponent."}
,{term:"Hit",source:"Natural Stat Trick",text:"A recorded body check that separates an opponent from the puck or disrupts possession."}
,{term:"Position-adjusted percentile",source:"Tracker",text:"A player's result compared with eligible players at the same broad position. A 90th percentile result is higher than roughly 90% of that peer group."}
,{term:"Season series",source:"Tracker",text:"The head-to-head results between two teams during the selected season."}
,{term:"Rest days",source:"Tracker",text:"Complete days between a team's previous game and the selected matchup."}
,{term:"Roster change",source:"Tracker",text:"A player added to or removed from the NHL roster feed since the previous automatic tracker update. It does not by itself explain the transaction type."}
,{term:"Retained salary",source:"PuckPedia",text:"A portion of a traded player's contract that remains charged to the former team's payroll and salary cap."}
,{term:"Waivers",source:"PuckPedia",text:"The process that can make a player available for other NHL teams to claim before an assignment or contract action is completed."}
,{term:"Signing bonus",source:"PuckPedia",text:"Guaranteed contract compensation paid on specified dates rather than as regular-season salary."}
,{term:"Projected lineup",source:"Daily Faceoff",text:"The forward lines, defence pairings and special-teams units expected to dress for an upcoming game. It can change before puck drop and should not be treated as confirmed."}
,{term:"Confirmed lineup",source:"Daily Faceoff",text:"A game-day lineup supported by a team announcement, warm-up observation or another cited report. Late changes can still occur."}
,{term:"Projected starting goalie",source:"Daily Faceoff",text:"The goaltender expected to start an upcoming game. The source page distinguishes projections from confirmed starts and shows when the status was updated."}
,{term:"Offer sheet",source:"PuckPedia",text:"A contract offered by one NHL team to another team’s restricted free agent. The original club can match it or receive draft-pick compensation determined by the contract value."}
,{term:"Qualifying offer",source:"PuckPedia",text:"A one-year contract offer a club must make to retain negotiating rights to an eligible restricted free agent. The required value depends on the player’s previous contract."}
,{term:"Salary arbitration",source:"PuckPedia",text:"A process in which an independent arbitrator determines a short-term salary after the player and club present their cases. Eligible players or clubs may elect it under CBA rules."}
,{term:"Form delta",source:"Tracker",text:"Recent points percentage minus season points percentage. A positive value means recent results are stronger than the team's full-season rate; a negative value means they are weaker."}
,{term:"Actual goals share",source:"Tracker",text:"Goals scored divided by total goals scored and allowed. Comparing it with expected-goals share highlights teams whose actual scoring results are running above or below their chance quality."}
,{term:"Goal-share gap",source:"Tracker",text:"Actual goals share minus expected-goals share. A large positive gap can reflect strong finishing or goaltending; a negative gap can identify results lagging the underlying chance profile."}
,{term:"Power Index movement",source:"Tracker",text:"Change in a team's Tracker Power Index rank between stored daily snapshots. Positive movement means the team has risen in the ranking."}
];
const guideMatch=label=>{const value=String(label).toLowerCase();return STAT_GUIDE.find(x=>x.term.toLowerCase()===value)||STAT_GUIDE.find(x=>value.includes(x.term.toLowerCase()))};
const GUIDE_CATEGORIES=["Results & standings","Team analytics","Players & skating","Goaltending","Games & schedule","Contracts & rosters","Tracker models"];
function guideCategory(x){const term=x.term.toLowerCase();if(x.source==="PuckPedia"||/roster change|waiver|retained salary/.test(term))return"Contracts & rosters";if(/save|goaltend|goalie|gsaa|gsax|goals-against|rebounds above expected/.test(term))return"Goaltending";if(x.source==="Daily Faceoff"||/season series|rest days|time on ice|penalty minutes|shots on goal|shot attempt|projected lineup|confirmed lineup/.test(term))return"Games & schedule";if(/individual|player impact|primary points|faceoff|takeaway|hit$|per 60|skating|shot speed|penalty impact|rush attempt|rebounds created|position-adjusted/.test(term))return"Players & skating";if(x.source==="Tracker")return"Tracker models";if(/games played|wins, losses|points \(pts\)|points percentage|goal differential|goals for and against|last 10|streak|wildcard|regulation wins/.test(term))return"Results & standings";return"Team analytics"}
const guideUsedIn=category=>({"Results & standings":"Dashboard · League · Playoffs","Team analytics":"Teams · Analytics · Power Rankings","Players & skating":"Players · Team profiles","Goaltending":"Goalie Centre · Players","Games & schedule":"Schedule · Game Centre","Contracts & rosters":"News & Offseason · Teams · Players","Tracker models":"Dashboard · Trends · Power Rankings · Playoffs"}[category]);
const metric=(label,value,detail="")=>{const help=guideMatch(label);return `<article class="metric"><div class="label">${label}${help?`<button class="metric-help" data-guide="${help.term}" title="Explain ${help.term}">?</button>`:""}</div><div class="value">${value}</div><div class="detail">${detail}</div></article>`};
const TABLE_HEADER_HELP={"Impact":"Composite position-adjusted percentile across primary scoring, expected goals, high-danger chances, rush attempts, takeaways and penalty impact.","Primary/60":"Goals plus primary assists per 60 minutes at five-on-five.","ixG/60":"Individual expected goals per 60 minutes at five-on-five.","HD/60":"Individual high-danger scoring chances per 60 minutes at five-on-five.","Penalty":"Penalties drawn minus penalties taken.","Pos":"Player position.","PTS%":"Percentage of all available standings points earned.","Form PTS%":"Percentage of available standings points earned during the selected recent-game window.","xG%":"Share of expected goals.","GD/GP":"Goal differential per game.","Form Δ":"Recent points percentage minus season points percentage.","Goal share":"Actual share of all goals scored and allowed.","Gap":"Actual goals share minus expected-goals share.","Index move":"Change in Tracker Power Index rank across stored snapshots.","P/G":"Points per game in the selected recent window.","Season P/G":"Full-season points per game.","Pace Δ":"Recent points-per-game rate minus season points-per-game rate.","GSAA":"Goals saved above the league-average rate.","GSAx":"Goals saved above expected based on shot quality."};
const teamTableCell=value=>{const original=String(value??"—"),plain=original.replace(/<[^>]*>/g,"").trim(),first=plain.split(/\s*[,/]\s*/)[0],standing=DATA?.standings?.find(r=>r.team===plain||r.name===plain||r.team===first||r.name===first);if(!standing)return original;if(original.includes("team-table-name"))return original;const tracked=teams().includes(standing.team);return`<span class="team-table-name ${tracked?"tracked":""}" style="--team-colour:${teamColour(standing.team)}">${tracked?`<strong>${safeText(plain)}</strong>`:safeText(plain)}</span>`};
const table=(headers,rows)=>{const teamColumn=headers.findIndex(x=>String(x).trim().toLowerCase()==="team");return`<table><thead><tr>${headers.map((x,i)=>{const help=TABLE_HEADER_HELP[x];return`<th scope="col" aria-sort="none"><button type="button" class="table-sort" data-sort-column="${i}" title="Sort by ${x}"><span class="${help?"defined-stat":""}"${help?` title="${help}"`:""}>${x}</span><span class="sort-indicator" aria-hidden="true">↕</span></button></th>`}).join("")}</tr></thead><tbody>${rows.length?rows.map(r=>`<tr>${r.map((x,i)=>`<td>${i===teamColumn?teamTableCell(x):x??"—"}</td>`).join("")}</tr>`).join(""):`<tr><td colspan="${headers.length}">No data available</td></tr>`}</tbody></table>`};
const tableSortValue=cell=>{const raw=cell.textContent.trim(),compact=raw.replace(/,/g,"").replace(/\s+/g," ");if(!compact||compact==="—"||compact==="-")return{missing:true,type:"text",value:""};if(/^\d{4}-\d{2}-\d{2}(?:\b|T)/.test(compact)){const value=Date.parse(compact.slice(0,10)+"T00:00:00Z");if(Number.isFinite(value))return{missing:false,type:"date",value}}const numeric=compact.replace(/^#/,"").replace(/%$/,"");if(/^[-+]?(?:\d+\.?\d*|\.\d+)$/.test(numeric))return{missing:false,type:"number",value:Number(numeric)};return{missing:false,type:"text",value:compact.toLocaleLowerCase()}};
function sortTable(button){const tableEl=button.closest("table"),body=tableEl?.tBodies?.[0],column=num(button.dataset.sortColumn),header=button.closest("th");if(!body||!header)return;const rows=[...body.rows].filter(row=>row.cells.length>column&&!row.cells[0]?.hasAttribute("colspan"));if(rows.length<2)return;const values=rows.map((row,index)=>({row,index,parsed:tableSortValue(row.cells[column])})),sample=values.find(x=>!x.parsed.missing)?.parsed,current=header.getAttribute("aria-sort"),direction=current==="ascending"?"descending":current==="descending"?"ascending":sample?.type==="number"||sample?.type==="date"?"descending":"ascending";tableEl.querySelectorAll("th").forEach(th=>{th.setAttribute("aria-sort","none");const indicator=th.querySelector(".sort-indicator");if(indicator)indicator.textContent="↕"});header.setAttribute("aria-sort",direction);button.querySelector(".sort-indicator").textContent=direction==="ascending"?"▲":"▼";values.sort((a,b)=>{if(a.parsed.missing!==b.parsed.missing)return a.parsed.missing?1:-1;let result=0;if(a.parsed.type==="text"||b.parsed.type==="text")result=String(a.parsed.value).localeCompare(String(b.parsed.value),undefined,{numeric:true,sensitivity:"base"});else result=a.parsed.value-b.parsed.value;return(result===0?a.index-b.index:direction==="ascending"?result:-result)}).forEach(x=>body.appendChild(x.row))}
const plot=(id,traces,layout={})=>{const css=getComputedStyle(document.documentElement),surface=css.getPropertyValue("--card").trim()||"#fff",text=css.getPropertyValue("--muted").trim()||"#64748b",grid=css.getPropertyValue("--line").trim()||"#e7ecf2";return Plotly.react(id,traces,{margin:{l:48,r:18,t:20,b:45},paper_bgcolor:surface,plot_bgcolor:surface,font:{family:"Arial, sans-serif",color:text},xaxis:{gridcolor:grid},yaxis:{gridcolor:grid},legend:{orientation:"h",y:-.2},...layout},{responsive:true,displaylogo:false})};
