const teams=()=>SELECTED_TEAMS||DATA.meta.trackedTeams,teamStanding=t=>DATA.standings.find(r=>r.team===t),allTeamCodes=()=>[...teams(),...DATA.standings.filter(r=>!teams().includes(r.team)).sort((a,b)=>a.name.localeCompare(b.name)).map(r=>r.team)],games=t=>DATA.teams[t]?.games||[],pct=s=>s?.gp?(s.points/(s.gp*2)*100):0;
const playersForTeam=t=>{const detailed=DATA.players[t]||[],byId=new Map(detailed.map(p=>[String(p.id),p])),roster=(DATA.rosters?.[t]||[]).map(p=>{const d=byId.get(String(p.id));return d?{...p,...d,name:p.name||d.name,headshot:p.headshot||d.headshot,number:p.number}:{...p,id:String(p.id),team:t,games:[],totals:{gp:0,goals:0,assists:0,points:0,saves:0}}});const rosterIds=new Set(roster.map(p=>String(p.id)));return [...roster,...detailed.filter(p=>!rosterIds.has(String(p.id)))].sort((a,b)=>a.name.localeCompare(b.name))};
