  el("dashboard-leaders").innerHTML=teams().map(t=>{const p=playerLeaders(t)[0];return `<div class="rank-row"><strong>${t}</strong><span>${p?`${p.name} · ${p.totals.points} PTS`:"—"}</span></div>`}).join("");
  const finals=DATA.games.filter(g=>g.finished&&teams().includes(g.team)).sort((a,b)=>safeDate(b).localeCompare(safeDate(a))).slice(0,12);el("dashboard-results").innerHTML=table(["Date","Team","Opponent","Result","Score"],finals.map(g=>[safeDate(g),g.team,g.opponent,g.result,`${g.gf}–${g.ga}`]));
  renderDivisionRaces();
