  el("analytics-table-title").textContent=`${division} Division performance matrix`;
  el("analytics-cards").innerHTML=metric("Division rank",rank?`#${rank}`:"—",division)+metric("Points percentage",`${pct(team).toFixed(1)}%`,`${team.points} points`)+metric("Goal differential",signed(team.gd),`${team.gf} for · ${team.ga} against`)+metric("Last 10",`${last.w}-${last.l}-${last.otl}`,`${last.pts} points`);
  plot("analytics-pct",[{type:"bar",x:divisionRows.map(r=>r.team),y:divisionRows.map(r=>r.points),marker:{color:divisionRows.map(r=>teamColour(r.team))}}],{showlegend:false,yaxis:{title:"Points",rangemode:"tozero",gridcolor:"#e5e8ec"}});
  plot("analytics-goals",[{type:"bar",x:divisionRows.map(r=>r.team),y:divisionRows.map(r=>r.gf),name:"Goals for",marker:{color:divisionRows.map(r=>teamColour(r.team))}},{type:"bar",x:divisionRows.map(r=>r.team),y:divisionRows.map(r=>r.ga),name:"Goals against",marker:{color:"rgba(0,0,0,0)",line:{color:divisionRows.map(r=>teamColour(r.team)),width:2}}}],{barmode:"group",bargap:.3});
