  const divisions=group(s,r=>r.division),divisionOrder=["Atlantic","Metropolitan","Central","Pacific"];el("division-tables").innerHTML=divisionOrder.filter(d=>divisions[d]).map(d=>`<article class="panel division-table"><h3>${d} Division</h3>${table(["#","Team","GP","W","L","OTL","PTS","GD"],divisions[d].sort((a,b)=>b.points-a.points).map((r,i)=>[i+1,`<span class="team-table-name ${tracked.has(r.team)?"tracked":""}" style="--team-colour:${teamColour(r.team)}">${tracked.has(r.team)?`<strong>${r.name}</strong>`:r.name}</span>`,r.gp,r.w,r.l,r.otl,`<strong>${r.points}</strong>`,signed(r.gd)]))}</article>`).join("");
  el("standings-table").innerHTML=table(["#","Team","Conference","Division","GP","W","L","OTL","PTS","RW","GF","GA","GD","Streak"],s.map((r,i)=>[i+1,r.name,r.conference,r.division,r.gp,r.w,r.l,r.otl,`<strong>${r.points}</strong>`,r.rw,r.gf,r.ga,signed(r.gd),r.streak]));
